var e=[{id:`L3_1`,type:`dialog`,speaker:`JOHN_MASON_NULL_NULL`,text:{KOREA:`허수공간 이탈! 자유낙하 중!`,JPN:`虚数空間を離脱！　自由落下中！`,ENG:`Exiting imaginary space! Freefalling!`,TWN:`脫離虛數空間，處於自由落體中！`},stage:{bg:`PROLOGUE_03`,slots:{L:null,C:{char_id:`JOHN_MASON_NULL_NULL`,face:`UNIT_SERIOUS`},R:null}}},{id:`L4_1`,type:`dialog`,speaker:`JOHN_MASON_NULL_NULL`,text:{KOREA:`목표 좌표 착지까지 32초!`,JPN:`目標座標に着地まで32秒！`,ENG:`32 seconds until landing on the target location!`,TWN:`距著陸目標座標還有32秒！`},stage:{bg:`PROLOGUE_03`,slots:{L:null,C:{char_id:`JOHN_MASON_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L5_1`,type:`dialog`,speaker:`JANE_MASON_NULL_NULL`,text:{KOREA:`너, 너무 흔들리잖아!`,JPN:`ゆ、揺れが激しすぎる！`,ENG:`I-isn't this thing shaking too much?`,TWN:`太、太晃了吧！`},stage:{bg:`PROLOGUE_03`,slots:{L:null,C:{char_id:`JANE_MASON_NULL_NULL`,face:`UNIT_SURPRISE`},R:null}}},{id:`L6_1`,type:`dialog`,speaker:`JANE_MASON_NULL_NULL`,text:{KOREA:`이거 정말 괜찮은 거 맞아?`,JPN:`これ、本当に大丈夫なの？`,ENG:`Are you sure this is okay?`,TWN:`這真的沒問題嗎？`},stage:{bg:`PROLOGUE_03`,slots:{L:null,C:{char_id:`JANE_MASON_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L7_1`,type:`dialog`,speaker:`JOHN_MASON_NULL_NULL`,text:{KOREA:`그야 카탈로그 스펙보다 두 배는 더 깊은 심도로 내려가고 있으니까!`,JPN:`そりゃ、カタログスペックより倍以上の深さに進んでるからな！`,ENG:`We're going almost twice as deep as what's written on its spec sheet.`,TWN:`那是因為我們正下落到比計數器顯示還要深兩倍的地方啊！`},stage:{bg:`PROLOGUE_03`,slots:{L:null,C:{char_id:`JOHN_MASON_NULL_NULL`,face:`UNIT_SERIOUS`},R:null}}},{id:`L8_1`,type:`dialog`,speaker:`JOHN_MASON_NULL_NULL`,text:{KOREA:`흔들리는 게 당연하지!`,JPN:`揺れて当然だ！`,ENG:`I'd be surprised if it weren't shaking.`,TWN:`會晃是當然的吧！`},stage:{bg:`PROLOGUE_03`,slots:{L:null,C:{char_id:`JOHN_MASON_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L12_1`,type:`dialog`,speaker:`TOMY_MASON_NULL_NULL`,text:{KOREA:`뭐, 뭐야?! 그거 위험하잖아!`,JPN:`な、なんだって！？　危ねえじゃねーか！`,ENG:`W-what?! Are you kidding me?`,TWN:`什，什麼啊？！那不是很危險嗎！`},stage:{bg:`PROLOGUE_03`,slots:{L:{char_id:`JERRY_MASON_NULL_NULL`,face:`UNIT_IDLE`},C:{char_id:`TOMY_MASON_NULL_NULL`,face:`UNIT_IDLE`},R:{char_id:`MICKEY_MASON_NULL_NULL`,face:`UNIT_IDLE`}}}},{id:`L13_1`,type:`dialog`,speaker:`JERRY_MASON_NULL_NULL`,text:{KOREA:`안 그래도 고철 처리장에서 주워온 것 같은 골동품인데!`,JPN:`そもそもが廃品処理場から拾ってきたようなおんぼろなのに！`,ENG:`This thing looked like it was picked up from a junkyard already!`,TWN:`這本來就是從廢鐵處理廠撿來的老古董啊！`},stage:{bg:`PROLOGUE_03`,slots:{L:{char_id:`JERRY_MASON_NULL_NULL`,face:`UNIT_IDLE`},C:{char_id:`TOMY_MASON_NULL_NULL`,face:`UNIT_IDLE`},R:{char_id:`MICKEY_MASON_NULL_NULL`,face:`UNIT_IDLE`}}}},{id:`L15_1`,type:`dialog`,speaker:`JOHN_MASON_NULL_NULL`,text:{KOREA:`걱정 마! 원래 이런 기계식 설계가 최신 하이테크 함선들보다 신뢰성이 더 높은 법......`,JPN:`心配するな！　元々こういう機械式設計のほうが最新のハイテク艦船よりも丈夫……`,ENG:`Don't worry! These old school mechanical designs are much more reliable than ships built with cutting edge technolo—`,TWN:`別擔心！通常這種機械的設計比最新的高科技艦船更可靠……`},stage:{bg:`PROLOGUE_03`,slots:{L:null,C:{char_id:`JOHN_MASON_NULL_NULL`,face:`UNIT_PRIDE`},R:null}}},{id:`L19_1`,type:`dialog`,speaker:`JANE_MASON_NULL_NULL`,text:{KOREA:`......방금 뭔가 아주 불길한 소리가 들리지 않았어?`,JPN:`……今、なんかすごく不吉な音しなかった？`,ENG:`Hey, what was that noise?`,TWN:`……剛剛是不是有什麼非常不祥的聲音？`},stage:{bg:`PROLOGUE_03`,slots:{L:{char_id:`JOHN_MASON_NULL_NULL`,face:`UNIT_IDLE`},C:null,R:{char_id:`JANE_MASON_NULL_NULL`,face:`UNIT_DESPAIR`}}}},{id:`L20_1`,type:`dialog`,speaker:`JOHN_MASON_NULL_NULL`,text:{KOREA:`기, 기분 탓이야! 기분 탓!`,JPN:`き、気のせいだ！　気のせい！`,ENG:`Y-you didn't hear anything! It's all in your head!`,TWN:`是、是錯覺啦！錯覺！`},stage:{bg:`PROLOGUE_03`,slots:{L:{char_id:`JOHN_MASON_NULL_NULL`,face:`UNIT_SERIOUS`},C:null,R:{char_id:`JANE_MASON_NULL_NULL`,face:`UNIT_DESPAIR`}}}},{id:`L21_1`,type:`dialog`,speaker:`JOHN_MASON_NULL_NULL`,text:{KOREA:`내 생각엔 아마 다이브 멀미 때문에 환청이 들리는......`,JPN:`俺が思うに、ダイブ酔いで幻聴がきこえるんじゃ……`,ENG:`Diving can cause several symptoms, and auditory hallucination is one of the most com—`,TWN:`我猜大概是躍入產生的噁心感，讓妳有幻聽了吧……`},stage:{bg:`PROLOGUE_03`,slots:{L:{char_id:`JOHN_MASON_NULL_NULL`,face:`UNIT_IDLE`},C:null,R:{char_id:`JANE_MASON_NULL_NULL`,face:`UNIT_DESPAIR`}}}},{id:`L24_1`,type:`dialog`,speaker:`JOOSHIYOON_FENRIR_NULL_NULL`,text:{KOREA:`아쉽지만 메이슨 씨, 환청은 아닌 것 같아요.`,JPN:`残念ながらメイソンさん、幻聴ではなさそうです。`,ENG:`I'm sorry, Mr. Mason, but it's not all in our heads.`,TWN:`非常遺憾，梅森先生，這好像不是幻聽。`},stage:{bg:`PROLOGUE_03`,slots:{L:null,C:{char_id:`JOOSHIYOON_FENRIR_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L25_1`,type:`dialog`,speaker:`JOOSHIYOON_FENRIR_NULL_NULL`,text:{KOREA:`저기 외벽에 균열이 가고 있거든요, 하하.`,JPN:`向こうの外壁に亀裂が入っているので、ハハ。`,ENG:`There's a crack on the hull, Hah hah.`,TWN:`那邊的外牆出現了裂縫喔，哈哈。`},stage:{bg:`PROLOGUE_03`,slots:{L:null,C:{char_id:`JOOSHIYOON_FENRIR_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L26_1`,type:`dialog`,speaker:`JOHN_MASON_NULL_NULL`,text:{KOREA:`뭐, 뭣?!`,JPN:`な、なにっ！？`,ENG:`W-what?!`,TWN:`啊，什麼？！`},stage:{bg:`PROLOGUE_03`,slots:{L:null,C:{char_id:`JOHN_MASON_NULL_NULL`,face:`UNIT_SURPRISE`},R:null}}}];export{e as default};